import{_ as t,o as e,c as n,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"X-Ray Offline System","text":"Technohub X-Ray Solution v2.4","tagline":"Sistem pemeriksaan kargo berbasis web dengan dukungan AI, penyimpanan lokal, dan integrasi multi-workstation.","actions":[{"theme":"brand","text":"Mulai Gunakan","link":"/getting-started"},{"theme":"alt","text":"Panduan Fitur","link":"/guide/input-data"}]},"features":[{"icon":"📦","title":"Manajemen Manifest","details":"Kelola data kargo melalui input manual atau impor massal via Excel. Dukungan MAWB, HAWB, ULD, dan tracking status scan."},{"icon":"🎥","title":"Screening Real-time","details":"Pengambilan gambar otomatis dari kamera Top View dan Side View dengan dukungan AI untuk deteksi koli."},{"icon":"🗄️","title":"Repository Lokal","details":"Seluruh data kargo, riwayat scan, dan gambar tersimpan di SQLite dan folder server — offline first."},{"icon":"🤖","title":"Deteksi AI","details":"Tiga metode deteksi koli: OpenCV (server-side), MediaPipe (client-side), atau Manual cropping."},{"icon":"📊","title":"Customs Dashboard","details":"Monitoring real-time untuk petugas bea cukai dengan metrik, panel detail, dan auto-refresh."},{"icon":"🔄","title":"Multi-Workstation","details":"Sinkronisasi data antar Workstation, Hub, dan Cloud dengan dukungan PostgreSQL."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),r={name:"index.md"};function s(o,a,d,l,u,g){return e(),n("div",null,[...a[0]||(a[0]=[i('<h2 id="fitur-utama" tabindex="-1">Fitur Utama <a class="header-anchor" href="#fitur-utama" aria-label="Permalink to &quot;Fitur Utama&quot;">​</a></h2><ul><li><strong>Manajemen Manifest:</strong> Pengelolaan data kargo melalui input manual atau impor massal via Excel.</li><li><strong>Screening Real-time:</strong> Pengambilan gambar otomatis dari kamera Top View dan Side View saat keputusan direkam.</li><li><strong>Penyimpanan Lokal (SQLite):</strong> Seluruh data kargo, riwayat scan, dan pengaturan tersimpan di database <code>xray.db</code>.</li><li><strong>Penyimpanan Gambar:</strong> Citra X-Ray disimpan sebagai file PNG lossless di folder <code>uploads/</code> pada server.</li><li><strong>Deteksi Koli Otomatis:</strong> Integrasi AI dengan OpenCV, MediaPipe, atau mode manual.</li><li><strong>Offline First:</strong> Seluruh operasional inti berjalan tanpa koneksi internet.</li><li><strong>Multi-Tingkat:</strong> Mendukung arsitektur Workstation, Hub, dan Cloud.</li></ul><h2 id="peran-aplikasi" tabindex="-1">Peran Aplikasi <a class="header-anchor" href="#peran-aplikasi" aria-label="Permalink to &quot;Peran Aplikasi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Peran</th><th>Deskripsi</th></tr></thead><tbody><tr><td><strong>Workstation</strong></td><td>Stasiun kerja pemeriksaan X-Ray individual. Input data screening dan scanning.</td></tr><tr><td><strong>Hub</strong></td><td>Server pusat yang mengkonsolidasi data dari beberapa Workstation.</td></tr><tr><td><strong>Cloud</strong></td><td>Server tingkat atas untuk agregasi data antar Hub dan pelaporan terpusat.</td></tr></tbody></table><h2 id="hak-akses" tabindex="-1">Hak Akses <a class="header-anchor" href="#hak-akses" aria-label="Permalink to &quot;Hak Akses&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>Akses</th></tr></thead><tbody><tr><td><strong>USER</strong></td><td>Data Cargo, Screening, Scan History, Settings</td></tr><tr><td><strong>CUSTOMS</strong></td><td>Hanya Customs Dashboard</td></tr><tr><td><strong>Admin</strong></td><td>Semua fitur + Manajemen Pengguna</td></tr></tbody></table>',6)])])}const p=t(r,[["render",s]]);export{m as __pageData,p as default};
